const body = $json.body ?? $json;

if (!body.case_id) throw new Error('Missing case_id');
if (!body.input_path) throw new Error('Missing input_path');
if (!body.model_path) throw new Error('Missing model_path');

const normalizePath = (value) => String(value).replace(/\\/g, '/');
const toBool = (value, defaultValue = false) => {
  if (value === undefined || value === null || value === '') return defaultValue;
  return value === true || String(value).toLowerCase() === 'true';
};
const repoRootRaw = body.repo_root ?? process.env.CHEST_CT_REPO_ROOT ?? '';
if (!repoRootRaw) throw new Error('Missing repo_root or CHEST_CT_REPO_ROOT');

const repoRoot = normalizePath(repoRootRaw);
const pythonExe = normalizePath(body.python_exe ?? process.env.CHEST_CT_PYTHON ?? `${repoRoot}/venv/Scripts/python.exe`);
const pipelineScript = normalizePath(`${repoRoot}/n8n/run_case_pipeline.py`);
const workDir = normalizePath(body.work_dir ? String(body.work_dir) : `${repoRoot}/n8n/runtime`);
const llmBaseModel = normalizePath(body.llm_base_model ?? process.env.CHEST_CT_LLM_BASE_MODEL ?? `${repoRoot}/models/llm/Llama-3.2-1B-Instruct`);
const llmAdapter = normalizePath(body.llm_adapter ?? process.env.CHEST_CT_LLM_ADAPTER ?? `${repoRoot}/llm/ct_report_pipeline/assets/models/lora_ct_report/llama32_20260520`);

return [{
  json: {
    case_id: String(body.case_id),
    input_path: normalizePath(body.input_path),
    model_path: normalizePath(body.model_path),
    repo_root: repoRoot,
    python_exe: pythonExe,
    pipeline_script: pipelineScript,
    work_dir: workDir,
    threshold: body.threshold !== undefined ? Number(body.threshold) : 0.5,
    device: body.device ? String(body.device) : 'cuda',
    medsam2_checkpoint: body.medsam2_checkpoint ? normalizePath(body.medsam2_checkpoint) : '',
    use_llm: toBool(body.use_llm, true),
    llm_base_model: llmBaseModel,
    llm_adapter: llmAdapter,
    llm_validate_output: toBool(body.llm_validate_output, true),
    no_propagate: toBool(body.no_propagate)
  }
}];

const n = $node['Normalize Input'].json;
const stdout = $json.stdout ?? '';
let finalState = {};
let stateParseError = '';

try {
  const start = stdout.indexOf('{');
  const end = stdout.lastIndexOf('}');
  if (start !== -1 && end > start) {
    finalState = JSON.parse(stdout.slice(start, end + 1));
  }
} catch (error) {
  stateParseError = String(error.message ?? error);
}

return [{
  json: {
    status: 'ok',
    case_id: n.case_id,
    repo_root: n.repo_root,
    python_exe: n.python_exe,
    work_dir: n.work_dir,
    state_json_path: `${n.work_dir}/${n.case_id}/state.json`,
    stages: ['preprocess','detect','segment','feature','report'],
    nodule_count: finalState.nodule_count ?? null,
    total_process_seconds: finalState.total_process_seconds ?? null,
    summary_html_path: finalState.summary_html_path ?? '',
    report_text_path: finalState.report_text_path ?? '',
    report_json_path: finalState.report_json_path ?? '',
    report_status: finalState.report_status ?? '',
    report_generation_method: finalState.report_generation_method ?? '',
    report_source_label: finalState.report_source_label ?? '',
    report_fallback_reason: finalState.report_fallback_reason ?? '',
    structured_input_path: finalState.structured_input_path ?? '',
    llm_structured_input_path: finalState.llm_structured_input_path ?? '',
    llm_raw_text_path: finalState.llm_raw_text_path ?? '',
    llm_postprocess_fix_count: finalState.llm_postprocess_fix_count ?? 0,
    llm_validation_fix_count: finalState.llm_validation_fix_count ?? 0,
    llm_base_model: finalState.llm_base_model ?? n.llm_base_model,
    llm_adapter: finalState.llm_adapter ?? n.llm_adapter,
    llm_validate_output: finalState.llm_validate_output ?? n.llm_validate_output,
    state_parse_error: stateParseError,
    report_stage_stdout: stdout
  }
}];
